Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWDuplicataAnuencia-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&CreDtaVct.IsEmpty() AND &CreDtaVct_To.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Vcto.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &CreDtaVct WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "à") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &CreDtaVct_To EndIf
If not (&CreRecPag.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Receber/Pagar") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &CreRecPag.EnumerationDescription() EndIf
If not (&CreSts.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Status") If Not &CreSts.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &CreSts.EnumerationDescription() Endif EndIf
If not (&CreDtaPrt.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &CreDtaPrt EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'CRECLICOD' &CreCliCod1.FromString(&GridStateDynamicFilter.Value) If not &CreCliCod1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cliente Cod." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CreCliCod1 EndIf Case &DynamicFiltersSelector1 = !'CRECLIRAZ' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CreCliRaz1.FromString(&GridStateDynamicFilter.Value) If not &CreCliRaz1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator1 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Cliente Nome", "Começa com") Case &DynamicFiltersOperator1 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Cliente Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreCliRaz1) EndIf Case &DynamicFiltersSelector1 = !'CREDUPNRO' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CreDupNro1.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator1 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Dup. Nro", "Começa com") Case &DynamicFiltersOperator1 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Dup. Nro", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreDupNro1) EndIf Case &DynamicFiltersSelector1 = !'CRECBRNOM' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CreCbrNom1.FromString(&GridStateDynamicFilter.Value) If not &CreCbrNom1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator1 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Cob. Nome", "Começa com") Case &DynamicFiltersOperator1 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Cob. Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreCbrNom1) EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'CRECLICOD' &CreCliCod2.FromString(&GridStateDynamicFilter.Value) If not &CreCliCod2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cliente Cod." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CreCliCod2 EndIf Case &DynamicFiltersSelector2 = !'CRECLIRAZ' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CreCliRaz2.FromString(&GridStateDynamicFilter.Value) If not &CreCliRaz2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator2 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Cliente Nome", "Começa com") Case &DynamicFiltersOperator2 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Cliente Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreCliRaz2) EndIf Case &DynamicFiltersSelector2 = !'CREDUPNRO' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CreDupNro2.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator2 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Dup. Nro", "Começa com") Case &DynamicFiltersOperator2 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Dup. Nro", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreDupNro2) EndIf Case &DynamicFiltersSelector2 = !'CRECBRNOM' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CreCbrNom2.FromString(&GridStateDynamicFilter.Value) If not &CreCbrNom2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator2 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Cob. Nome", "Começa com") Case &DynamicFiltersOperator2 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Cob. Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreCbrNom2) EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'CRECLICOD' &CreCliCod3.FromString(&GridStateDynamicFilter.Value) If not &CreCliCod3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cliente Cod." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CreCliCod3 EndIf Case &DynamicFiltersSelector3 = !'CRECLIRAZ' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CreCliRaz3.FromString(&GridStateDynamicFilter.Value) If not &CreCliRaz3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator3 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Cliente Nome", "Começa com") Case &DynamicFiltersOperator3 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Cliente Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreCliRaz3) EndIf Case &DynamicFiltersSelector3 = !'CREDUPNRO' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CreDupNro3.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator3 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Dup. Nro", "Começa com") Case &DynamicFiltersOperator3 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Dup. Nro", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreDupNro3) EndIf Case &DynamicFiltersSelector3 = !'CRECBRNOM' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CreCbrNom3.FromString(&GridStateDynamicFilter.Value) If not &CreCbrNom3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator3 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Cob. Nome", "Começa com") Case &DynamicFiltersOperator3 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Cob. Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreCbrNom3) EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Seq." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Número" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Cliente" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Emissão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Vencimento" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Valor" &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "Saldo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = "L. C." &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = "Bloqueto" &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Text = "Protesto" &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Text = "Vend." &ExcelDocument.Cells(&CellRow, &FirstColumn + 11).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 11).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 11).Text = "Pedido"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod CreRecPag FilCod CreDtaVct when &OrderedBy = 1 order CreCod when &OrderedBy = 2 AND &OrderedDsc = False order (CreCod) when &OrderedBy = 2 AND &OrderedDsc = True order CreDupNro when &OrderedBy = 3 AND &OrderedDsc = False order (CreDupNro) when &OrderedBy = 3 AND &OrderedDsc = True order CreDtaEms when &OrderedBy = 4 AND &OrderedDsc = False order (CreDtaEms) when &OrderedBy = 4 AND &OrderedDsc = True order CreDtaVct when &OrderedBy = 5 AND &OrderedDsc = False order (CreDtaVct) when &OrderedBy = 5 AND &OrderedDsc = True order CreVlrDup when &OrderedBy = 6 AND &OrderedDsc = False order (CreVlrDup) when &OrderedBy = 6 AND &OrderedDsc = True order CreVlrSdo when &OrderedBy = 7 AND &OrderedDsc = False order (CreVlrSdo) when &OrderedBy = 7 AND &OrderedDsc = True order CreBloNro when &OrderedBy = 8 AND &OrderedDsc = False order (CreBloNro) when &OrderedBy = 8 AND &OrderedDsc = True order CreDtaPrt when &OrderedBy = 9 AND &OrderedDsc = False order (CreDtaPrt) when &OrderedBy = 9 AND &OrderedDsc = True order CreVenCod when &OrderedBy = 10 AND &OrderedDsc = False order (CreVenCod) when &OrderedBy = 10 AND &OrderedDsc = True order CrePedCod when &OrderedBy = 11 AND &OrderedDsc = False order (CrePedCod) when &OrderedBy = 11 AND &OrderedDsc = True
using DSWWDuplicataAnuencia(&CreDtaVct, &CreDtaVct_To, &CreRecPag, &CreSts, &CreDtaPrt, &DynamicFiltersSelector1 , &DynamicFiltersOperator1, &CreCliCod1, &CreCliRaz1, &CreDupNro1, &CreCbrNom1, &DynamicFiltersEnabled2 , &DynamicFiltersSelector2, &DynamicFiltersOperator2, &CreCliCod2, &CreCliRaz2, &CreDupNro2, &CreCbrNom2 , &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &DynamicFiltersOperator3, &CreCliCod3, &CreCliRaz3, &CreDupNro3 , &CreCbrNom3)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = CreCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(CreDupNro) &gridCreCliCodRaz = CreCliCodRaz &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = WWP_Export_SecureText(&gridCreCliCodRaz) &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = CreDtaEms &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Date = CreDtaVct &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Number = CreVlrDup &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Number = CreVlrSdo &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Number = CreCbrCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = WWP_Export_SecureText(CreBloNro) &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Date = CreDtaPrt &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Number = CreVenCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 11).Number = CrePedCod
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWDuplicataAnuenciaGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWDuplicataAnuenciaGridState")) Else &GridState.FromXml(&Session.Get(!"WWDuplicataAnuenciaGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"CREDTAVCT" &CreDtaVct.FromString(&GridStateFilterValue.Value) &CreDtaVct_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"CRERECPAG" &CreRecPag.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRESTS" &CreSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREDTAPRT" &CreDtaPrt.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
